// pickDiscount randomly selects one of the allowed discount percentages.
// Because this runs inside an Activity (not inside Workflow code), using
// Math.random() here is perfectly safe and replay-deterministic.
export async function pickDiscount(): Promise<number> {
  const options = [0, 5, 10, 15, 20];
  const idx = Math.floor(Math.random() * options.length);
  return options[idx];
}

// DiscountWorkflow picks a percentage discount for a user.
//
// Time is obtained via `workflow.now()` (deterministic Workflow-safe API).
// Random discount selection is delegated to the `pickDiscount` Activity so
// that the Workflow body remains fully deterministic and replay-safe.

import { proxyActivities, now } from '@temporalio/workflow';
import type * as activities from './activities';

const { pickDiscount } = proxyActivities<typeof activities>({
  startToCloseTimeout: '10 seconds',
});

export interface DiscountResult {
  userId: string;
  discount: number;
  decidedAt: number;
}

export async function DiscountWorkflow(userId: string): Promise<DiscountResult> {
  // Delegate randomness to an Activity – safe for replay.
  const discount = await pickDiscount();
  // Obtain deterministic Workflow time instead of wall-clock new Date().
  const decidedAt = now();
  return { userId, discount, decidedAt };
}

